static void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

static void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

static void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

static void show_progress_done(void) { flushed_printf("\n"); }

template <int N, class F>
static double benchmark(F&& f) {
  double best = std::numeric_limits<double>::infinity();
  for (int i = 0; i < N; ++i) best = std::min(best, f());
  return best;
}

static float half_to_float(std::uint16_t h) {
  const std::uint32_t sign = (std::uint32_t)(h & 0x8000u) << 16;
  std::uint32_t exp = (h >> 10) & 0x1Fu;
  std::uint32_t mant = h & 0x03FFu;
  std::uint32_t fbits = 0;

  if (exp == 0x1Fu) {
    fbits = sign | 0x7F800000u | (mant << 13);
  } else if (exp != 0) {
    exp = exp + (127u - 15u);
    fbits = sign | (exp << 23) | (mant << 13);
  } else if (mant != 0) {
    int e = -14;
    while ((mant & 0x0400u) == 0) {
      mant <<= 1;
      --e;
    }
    mant &= 0x03FFu;
    const std::uint32_t exp32 = (std::uint32_t)(e + 127) << 23;
    fbits = sign | exp32 | (mant << 13);
  } else {
    fbits = sign;
  }

  float out;
  std::memcpy(&out, &fbits, sizeof(out));
  return out;
}

struct FloatOps {
  using reg_type = float;
  using mem_type = float;

  static reg_type zero() { return 0.0f; }
  static reg_type seed() { return 1.0f; }
  static reg_type neg_one() { return -1.0f; }
  static reg_type load(const volatile mem_type& v) { return v; }
  static reg_type mad(reg_type a, reg_type s) { return a * a + s; }
  static reg_type mul(reg_type a, reg_type b) { return a * b; }
  static reg_type add(reg_type a, reg_type b) { return a + b; }
  static bool is_equal(reg_type a, reg_type b) { return a == b; }
};

struct DoubleOps {
  using reg_type = double;
  using mem_type = double;

  static reg_type zero() { return 0.0; }
  static reg_type seed() { return 1.0; }
  static reg_type neg_one() { return -1.0; }
  static reg_type load(const volatile mem_type& v) { return v; }
  static reg_type mad(reg_type a, reg_type s) { return a * a + s; }
  static reg_type mul(reg_type a, reg_type b) { return a * b; }
  static reg_type add(reg_type a, reg_type b) { return a + b; }
  static bool is_equal(reg_type a, reg_type b) { return a == b; }
};

struct IntOps {
  using reg_type = std::int32_t;
  using mem_type = std::int32_t;

  static reg_type zero() { return 0; }
  static reg_type seed() { return 1; }
  static reg_type neg_one() { return -1; }
  static reg_type load(const volatile mem_type& v) { return v; }

  static reg_type mad(reg_type a, reg_type s) {
    const std::uint32_t ua = static_cast<std::uint32_t>(a);
    const std::uint32_t us = static_cast<std::uint32_t>(s);
    return static_cast<reg_type>(ua * ua + us);
  }

  static reg_type mul(reg_type a, reg_type b) {
    const std::uint32_t ua = static_cast<std::uint32_t>(a);
    const std::uint32_t ub = static_cast<std::uint32_t>(b);
    return static_cast<reg_type>(ua * ub);
  }

  static reg_type add(reg_type a, reg_type b) {
    const std::uint32_t ua = static_cast<std::uint32_t>(a);
    const std::uint32_t ub = static_cast<std::uint32_t>(b);
    return static_cast<reg_type>(ua + ub);
  }

  static bool is_equal(reg_type a, reg_type b) { return a == b; }
};

struct HalfOps {
  using reg_type = HalfReg;
  using mem_type = HalfMem;

  static reg_type zero() { return {0.0f, 0.0f}; }
  static reg_type seed() { return {1.0f, 1.0f}; }
  static reg_type neg_one() { return {-1.0f, -1.0f}; }

  static reg_type load(const volatile mem_type& v) {
    const std::uint16_t x = v.x;
    const std::uint16_t y = v.y;
    return {half_to_float(x), half_to_float(y)};
  }

  static reg_type mad(reg_type a, reg_type s) {
    return {a.x * a.x + s.x, a.y * a.y + s.y};
  }

  static reg_type mul(reg_type a, reg_type b) {
    return {a.x * b.x, a.y * b.y};
  }

  static reg_type add(reg_type a, reg_type b) {
    return {a.x + b.x, a.y + b.y};
  }

  static bool is_equal(reg_type a, reg_type b) {
    return a.x == b.x && a.y == b.y;
  }
};

template <class Ops>
static double run_kernel(volatile typename Ops::mem_type* data,
                         long size,
                         bool block_strided,
                         size_t workgroupsize,
                         unsigned int elements_per_wi,
                         unsigned int fusion_degree,
                         int current_compute_iterations) {
  constexpr int total_bench_iterations = 3;

  return benchmark<total_bench_iterations>([&]() {
    const long compute_grid_size =
        size / static_cast<long>(elements_per_wi) /
        static_cast<long>(fusion_degree);
    const long num_groups = compute_grid_size / static_cast<long>(workgroupsize);

    long long hits = 0;
    const double ts_start = omp_get_wtime();

#pragma omp parallel reduction(+ : hits)
    {
      auto* tmps = new typename Ops::reg_type[elements_per_wi];

#pragma omp for schedule(static)
      for (long gid = 0; gid < compute_grid_size; ++gid) {
        const long local_id = gid % static_cast<long>(workgroupsize);
        const long group_id = gid / static_cast<long>(workgroupsize);
        const long stride =
            block_strided ? static_cast<long>(workgroupsize) : compute_grid_size;
        const long idx =
            block_strided
                ? group_id * static_cast<long>(workgroupsize) *
                      static_cast<long>(elements_per_wi) +
                      local_id
                : gid;
        const long big_stride =
            num_groups * static_cast<long>(workgroupsize) *
            static_cast<long>(elements_per_wi);
        const auto seed = Ops::seed();

        for (unsigned int k = 0; k < fusion_degree; ++k) {
          for (unsigned int j = 0; j < elements_per_wi; ++j) {
            auto tmp = Ops::load(
                data[idx + static_cast<long>(j) * stride +
                     static_cast<long>(k) * big_stride]);
            for (int i = 0; i < current_compute_iterations; ++i) {
              tmp = Ops::mad(tmp, seed);
            }
            tmps[j] = tmp;
          }

          auto sum = Ops::zero();
          for (unsigned int j = 0; j < elements_per_wi; j += 2) {
            sum = Ops::add(sum, Ops::mul(tmps[j], tmps[j + 1]));
          }

          if (Ops::is_equal(sum, Ops::neg_one())) ++hits;
        }
      }

      delete[] tmps;
    }

    const double duration = (omp_get_wtime() - ts_start) * 1000.0;
    g_dummy_hits += hits;
    return duration;
  });
}

static void runbench_warmup(volatile std::int16_t* data,
                            long size,
                            size_t workgroupsize) {
  (void)workgroupsize;
  const long reduced_grid_size = size / 256;
#pragma omp parallel for schedule(static)
  for (long i = 0; i < reduced_grid_size; ++i) {
    volatile std::int16_t v = data[i];
    (void)v;
  }
}

void mixbenchCPU(void* buffer, size_t size_bytes) {
  const bool block_strided = false;
  const bool host_allocated = true;
  const bool use_os_timer = true;
  const size_t workgroupsize = 256;
  const unsigned int elements_per_wi = 8;
  const unsigned int fusion_degree = 4;

  const long size = static_cast<long>(size_bytes / sizeof(double));

  printf("Workitem stride:        %s\n",
         block_strided ? "Workgroup" : "NDRange");
  printf("Buffer allocation:      %s\n",
         host_allocated ? "Host allocated" : "Device allocated");
  printf("Timer:                  %s\n",
         use_os_timer ? "OS based" : "CL event based");

  std::memset(buffer, 0, size_bytes);

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    show_progress_step(0, '/');
    show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(reinterpret_cast<volatile std::int16_t*>(buffer), size,
                  workgroupsize);

  double kernel_time_mad_sp[compute_iterations_len];
  double kernel_time_mad_dp[compute_iterations_len];
  double kernel_time_mad_hp[compute_iterations_len];
  double kernel_time_mad_int[compute_iterations_len];

  std::memset(buffer, 0, size_bytes);
  for (int i = 0; i < compute_iterations_len; ++i) {
    kernel_time_mad_sp[i] = run_kernel<FloatOps>(
        reinterpret_cast<volatile float*>(buffer), size, block_strided,
        workgroupsize, elements_per_wi, fusion_degree, compute_iterations[i]);
  }

  std::memset(buffer, 0, size_bytes);
  for (int i = 0; i < compute_iterations_len; ++i) {
    kernel_time_mad_int[i] = run_kernel<IntOps>(
        reinterpret_cast<volatile std::int32_t*>(buffer), size, block_strided,
        workgroupsize, elements_per_wi, fusion_degree, compute_iterations[i]);
  }

  std::memset(buffer, 0, size_bytes);
  for (int i = 0; i < compute_iterations_len; ++i) {
    kernel_time_mad_dp[i] = run_kernel<DoubleOps>(
        reinterpret_cast<volatile double*>(buffer), size, block_strided,
        workgroupsize, elements_per_wi, fusion_degree, compute_iterations[i]);
  }

  std::memset(buffer, 0, size_bytes);
  for (int i = 0; i < compute_iterations_len; ++i) {
    kernel_time_mad_hp[i] = run_kernel<HalfOps>(
        reinterpret_cast<volatile HalfMem*>(buffer), size, block_strided,
        workgroupsize, elements_per_wi, fusion_degree, compute_iterations[i]);
  }

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    const long compute_grid_size =
        size / static_cast<long>(elements_per_wi) /
        static_cast<long>(fusion_degree);
    const int current_compute_iterations = compute_iterations[i];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2LL * elements_per_wi * current_compute_iterations) *
             (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp[i],
        ((double)computations) / kernel_time_mad_sp[i] * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp[i] *
            1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp[i],
        ((double)computations) / kernel_time_mad_dp[i] * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp[i] *
            1000. / (1000. * 1000. * 1000.),
        ((double)2 * computations) / ((double)memoryoperations * 4.0),
        kernel_time_mad_hp[i],
        ((double)2 * computations) / kernel_time_mad_hp[i] * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * 4.0) / kernel_time_mad_hp[i] * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int[i],
        ((double)computations) / kernel_time_mad_int[i] * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int[i] *
            1000. / (1000. * 1000. * 1000.));
  }

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");
}
